{
  "title": "बड़े फ़ाइल ट्रांसफ़र",
  "group": "S3 ट्रांसफ़र",
  "options": [
    {
      "text": "हमेशा एकल PUT अनुरोध का उपयोग करें"
    },
    {
      "text": "बड़ी फ़ाइलों के लिए मल्टीपार्ट अपलोड का उपयोग करें",
      "hint": "S3 के लिए अनुशंसित तरीका"
    },
    {
      "text": "अपलोड करने से पहले संपीड़ित करें",
      "hint": "फ़ाइल आकार कम कर सकता है"
    },
    {
      "text": "अपलोड से पहले मैन्युअल रूप से विभाजित करें",
      "hint": "असुविधाजनक हो सकता है"
    }
  ],
  "questionProse": [
    "S3 में बड़ी फ़ाइलों को अपलोड करने का सबसे अच्छा तरीका क्या है?"
  ],
  "explanationProse": [
    "मल्टीपार्ट अपलोड लाभ:\n    - बड़ी फ़ाइलों को कुशलता से हैंडल करें\n    - अंतर्विरोध अपलोड को फिर से शुरू करें\n    - फ़ाइल भागों का समानांतर अपलोड\n    - 100MB से अधिक फ़ाइलों के लिए अनुशंसित\n    - नेटवर्क विश्वसनीयता में सुधार\n\n    [S3 मल्टीपार्ट अपलोड](https://docs.aws.amazon.com/AmazonS3/latest/userguide/mpuoverview.html)"
  ]
}
